package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.util.Collections;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CartTest {

  private Cart cart;
  private List<LineItem> lineItems;
  private String buyerName;
  private String creditCard;

  @BeforeEach
  public void setUp() {
    lineItems = Collections.emptyList();
    buyerName = "John Doe";
    creditCard = "1234-5678-9012-3456";
  }

  @Test
  public void testGetCreditCard() throws Exception {
    // Use reflection to instantiate Cart since constructor is not visible
    Constructor<?> constructor = Class.forName("com.google.gson.examples.android.model.Cart")
        .getDeclaredConstructor(List.class, String.class, String.class);
    constructor.setAccessible(true);
    cart = (Cart) constructor.newInstance(lineItems, buyerName, creditCard);

    // Verify getCreditCard returns correct credit card
    assertEquals(creditCard, cart.getCreditCard());
  }

  @Test
  public void testGetCreditCardWithReflectionSet() throws Exception {
    // Create instance with dummy values
    Constructor<?> constructor = Class.forName("com.google.gson.examples.android.model.Cart")
        .getDeclaredConstructor(List.class, String.class, String.class);
    constructor.setAccessible(true);
    cart = (Cart) constructor.newInstance(lineItems, buyerName, "initialCard");

    // Use reflection to change private final creditCard field
    Field creditCardField = Class.forName("com.google.gson.examples.android.model.Cart")
        .getDeclaredField("creditCard");
    creditCardField.setAccessible(true);
    creditCardField.set(cart, creditCard);

    // Verify getCreditCard returns updated credit card
    assertEquals(creditCard, cart.getCreditCard());
  }
}
